declare(strict_types=1);require __DIR__.'/config.php';require_admin();require __DIR__.'/patient-layout.php';$pdo=db();$driver=$pdo->getAttribute(PDO::ATTR_DRIVER_NAME);
$pdo->exec($driver==='sqlite'?"CREATE TABLE IF NOT EXISTS employees(id INTEGER PRIMARY KEY AUTOINCREMENT,full_name TEXT NOT NULL,email TEXT NOT NULL UNIQUE,start_date DATE NOT NULL,end_date DATE NULL,job_title TEXT NOT NULL,created_at DATETIME DEFAULT CURRENT_TIMESTAMP)":"CREATE TABLE IF NOT EXISTS employees(id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,full_name VARCHAR(190) NOT NULL,email VARCHAR(190) NOT NULL UNIQUE,start_date DATE NOT NULL,end_date DATE NULL,job_title VARCHAR(190) NOT NULL,created_at DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");$message='';$error='';
