<main class="patient-container employee-page"><nav class="settings-tabs"><a href="<?=url('admin.php')?>">Kullanıcı Yönetimi</a><a href="<?=url('branches.php')?>">Şubeler</a><a class="active" href="<?=url('employees.php')?>">Çalışanlar</a></nav><?php if($message):?><div class="notice success"><?=e($message)?></div><?php endif?><?php if($error):?><div class="notice error"><?=e($error)?></div><?php endif?><section class="employee-card"><header><h1><?=$edit?'Çalışanı Düzenle':'Yeni Çalışan'?></h1></header><form method="post" class="employee-form"><input type="hidden" name="csrf" value="<?=csrf()?>"><input type="hidden" name="id" value="<?=(int)($edit['id']??0)?>"><label>Ad Soyad<input name="full_name" value="<?=e($edit['full_name']??'')?>" required></label><label>E-posta<input type="email" name="email" value="<?=e($edit['email']??'')?>" required></label><label>Giriş Tarihi<input type="date" name="start_date" value="<?=e($edit['start_date']??date('Y-m-d'))?>" required></label><label>Çıkış Tarihi<input type="date" name="end_date" value="<?=e($edit['end_date']??'')?>"></label><label>Görevi<input name="job_title" value="<?=e($edit['job_title']??'')?>" required></label><div class="actions"><button>Kaydet</button><?php if($edit):?><a href="<?=url('employees.php')?>">İptal</a><?php endif?></div></form></section><section class="employee-card"><header><h2>Çalışan Listesi</h2><p><?=count($employees)?> kayıt</p></header><div class="table-scroll"><table><thead><tr><th>Ad Soyad</th><th>E-posta</th><th>Giriş Tarihi</th><th>Çıkış Tarihi</th><th>Görevi</th><th>İşlemler</th></tr></thead><tbody><?php foreach($employees as $x):?><tr><td><b><?=e($x['full_name'])?></b></td><td><?=e($x['email'])?></td><td><?=format_date_tr($x['start_date'])?></td><td><?=$x['end_date']?format_date_tr($x['end_date']):'—'?></td><td><?=e($x['job_title'])?></td><td><a class="edit" href="<?=url('employees.php?edit='.(int)$x['id'])?>">Düzenle</a><form method="post" onsubmit="return confirm('Bu çalışan silinsin mi?')"><input type="hidden" name="csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?=(int)$x['id']?>"><button class="delete">Sil</button></form></td></tr><?php endforeach?><?php if(!$employees):?><tr><td colspan="6">Henüz çalışan kaydı bulunmuyor.</td></tr><?php endif?></tbody></table></div></section></main>
